// mm/src/api/refresh.js
import axios from 'axios';

const DEFAULT_API_BASE = 'https://manuscriptmagic.ai';
const API_BASE = process.env.REACT_APP_API_BASE_URL || DEFAULT_API_BASE;

const ACCESS_KEY = 'mm_accessToken';
const REFRESH_KEY = 'mm_refreshToken';
const ACCESS_CREATED_KEY = 'mm_accessTokenCreatedAt';

function getRefreshToken() {
  return localStorage.getItem(REFRESH_KEY) || '';
}

function setTokens({ accessToken, refreshToken }) {
  if (accessToken) {
    localStorage.setItem(ACCESS_KEY, accessToken);
    localStorage.setItem(ACCESS_CREATED_KEY, Date.now().toString());
  }
  if (refreshToken) {
    localStorage.setItem(REFRESH_KEY, refreshToken);
  }
}

/**
 * refresh.php
 * Expects: multipart/form-data with key "refreshToken"
 * No Authorization header required.
 *
 * Should return something like:
 *   { success: true, accessToken: "...", refreshToken?: "..." }
 */
export async function refreshTokens() {
  const refreshToken = getRefreshToken();
  if (!refreshToken) {
    throw new Error('Missing refresh token');
  }

  const url = `${API_BASE}/refresh.php`;

  const form = new FormData();
  form.append('refreshToken', refreshToken);

  const res = await axios.post(url, form, {
    headers: {
      Accept: 'application/json',
      // Do NOT set Content-Type manually; browser will add boundary.
    },
  });

  const data = res.data || {};

  // Normalize common response shapes:
  const newAccessToken = data.accessToken || data.AccessToken || data.token || null;
  const newRefreshToken = data.refreshToken || data.RefreshToken || null;

  if (!newAccessToken) {
    throw new Error(data?.message || 'refresh.php did not return an accessToken');
  }

  setTokens({ accessToken: newAccessToken, refreshToken: newRefreshToken });

  return {
    accessToken: newAccessToken,
    refreshToken: newRefreshToken || refreshToken,
  };
}

/**
 * Wrap an API call and retry once if we get a 401 by refreshing tokens.
 * Usage:
 *   return withAuthRetry(() => axios.get(...))
 */
export async function withAuthRetry(requestFn) {
  try {
    return await requestFn();
  } catch (err) {
    const status = err?.response?.status;

    if (status === 401) {
      // Attempt refresh, then retry once
      await refreshTokens();
      return await requestFn();
    }

    throw err;
  }
}
